# Search for "لا تزوج" "لا تنكح" etc in hadith
def find_substring(substr):
    res = []
    for rec in hadith_data:
        text = (rec.get('hadithTxt') or '') + ' ' + (rec.get('Matn') or '')
        if substr in text:
            res.append((rec['hadithID'], rec['title'], text[:3000]))
    return res

results = find_substring('لا تزوج')
